try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    const business = $node['Split In Batches'].json;
    let competitors = [];
    try {
      competitors = JSON.parse(business.competitors);
    } catch(e) {
      competitors = business.competitors.split(',').map(c => c.trim());
    }
    const firstCompetitor = competitors[0] || '';
    results.push({json: {
      business_id: business.id,
      business_name: business.business_name || '',
      email: business.email || '',
      competitor_name: firstCompetitor,
      all_competitors: competitors
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message}}];
}

