try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    const content = item.json.content && item.json.content[0] ? item.json.content[0].text : '';
    let parsed;
    try {
      parsed = JSON.parse(content);
    } catch(e) {
      const match = content.match(/\{[\s\S]*\}/);
      if (match) {
        parsed = JSON.parse(match[0]);
      } else {
        parsed = {
          competitor_name: $node['Parse Competitors'].json.competitor_name,
          key_findings: ['Competitor is active on social media'],
          threats: ['Price competition'],
          opportunities: ['Differentiation through service quality'],
          recommended_actions: ['Monitor competitor pricing', 'Improve content quality'],
          urgency_level: 'medium'
        };
      }
    }
    results.push({json: {
      business_id: $node['Parse Competitors'].json.business_id,
      business_name: $node['Parse Competitors'].json.business_name,
      email: $node['Parse Competitors'].json.email,
      competitor_name: parsed.competitor_name || $node['Parse Competitors'].json.competitor_name,
      key_findings: parsed.key_findings || [],
      threats: parsed.threats || [],
      opportunities: parsed.opportunities || [],
      recommended_actions: parsed.recommended_actions || [],
      urgency_level: parsed.urgency_level || 'medium',
      created_at: new Date().toISOString()
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message, business_id: $node['Parse Competitors'].json.business_id}}];
}
